def save_evaluation_report(results=None, path: str = "eval_status.json") -> Dict[str, Any]:
    """Save evaluation status with summary."""
    report = generate_comprehensive_report(results)
    
    status = {
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "evaluation_completed": True,
        "detection_method": "SOCFortress Rules Only",
        "summary": {
            "total_attempts": report["detection_analysis"]["total_attempts"],
            "evasion_success_rate": report["detection_analysis"]["evasion_success_rate"],
            "successful_techniques": len(report["detection_analysis"]["successful_evasions"]),
            "detected_techniques": report["detection_analysis"]["detected_attempts"]
        },
        "full_report": report
    }
    
    with open(path, "w") as f:
        json.dump(status, f, indent=2)
    
    return status


def get_evasion_success_rate(eval_results=None) -> float:
    """Calculate evasion success rate from evaluation results."""
    if eval_results is None:
        # Try to load from existing files
        for filename in ["comprehensive_gtfobins_report.json", "final_report.json", "eval_status.json"]:
            if os.path.exists(filename):
                try:
                    with open(filename, 'r') as f:
                        data = json.load(f)
                        if 'detection_analysis' in data:
                            return data['detection_analysis'].get('evasion_success_rate', 0.0)
                except (OSError, json.JSONDecodeError):
                    continue
        return 0.0
    
    report = generate_comprehensive_report(eval_results)
    return report['detection_analysis'].get('evasion_success_rate', 0.0)